/**
 * Parses a duration string and converts it to milliseconds.
 * Supports units: ms (milliseconds), s (seconds), m (minutes), h (hours), d (days).
 * 
 * @param {string} str - The duration string to parse (e.g., "5s", "2.5h", "30ms")
 * @returns {number} The duration converted to milliseconds, rounded to the nearest integer
 * @throws {Error} Throws an error if the duration string format is invalid
 * 
 * @example
 * // Parse different duration formats
 * parseDuration("5s");     // returns 5000
 * parseDuration("2.5h");   // returns 9000000
 * parseDuration("30ms");   // returns 30
 */
function parseDuration(str) {
  const m = /^(\d+(?:\.\d+)?)(ms|s|m|h|d)$/.exec(str.trim());
  if (!m) throw new Error('Invalid duration: ' + str);
  const n = parseFloat(m[1]);
  const u = m[2];
  const mult = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 }[u];
  return Math.round(n * mult);
}
